// Load fontawesome mapped icons
@use "@acorex/styles/icons/fontawesome/index.scss" as *;

// Load fontawesome font
@use "../public/fonts/fontawesome/styles/index.scss" as *;

// Load material icons mapped icons
@use "@acorex/styles/icons/material/index.scss" as *;

// Load material icons font
@use "../public/fonts/material/styles/index.scss" as *;

// Load huge icons mapped icons based on the style you want to use
@import "@acorex/styles/icons/huge/huge-bulk/index.scss";
// @import "@acorex/styles/icons/huge/huge-duotone/index.scss";
// @import "@acorex/styles/icons/huge/huge-solid-rounded/index.scss";
// @import "@acorex/styles/icons/huge/huge-solid-sharp/index.scss";
// @import "@acorex/styles/icons/huge/huge-solid-standard/index.scss";
// @import "@acorex/styles/icons/huge/huge-stroke-rounded/index.scss";
// @import "@acorex/styles/icons/huge/huge-stroke-sharp/index.scss";
// @import "@acorex/styles/icons/huge/huge-stroke-standard/index.scss";
// @import "@acorex/styles/icons/huge/huge-twotone/index.scss";

// Load huge icons font
@use "../public/fonts/huge/styles/index.scss" as *;

@use './variables';

.ax-icon-thin {
  --ax-sys-icon-weight: 100;
}
.ax-icon-light {
  --ax-sys-icon-weight: 300;
}
.ax-icon-regular {
  --ax-sys-icon-weight: 400;
}
.ax-icon-solid {
  --ax-sys-icon-weight: 900;
}
.ax-icon {
  -moz-osx-font-smoothing: grayscale;
  -webkit-font-smoothing: antialiased;
  display: inline-flex !important;
  align-items: center;
  justify-content: center;
  font-style: normal;
  font-variant: normal;
  text-rendering: auto;
  font-family: 'Font Awesome 6 Pro';
  width: var(--ax-sys-icon-width, inherit);
  height: var(--ax-sys-icon-height, inherit);
  font-weight: var(--ax-sys-icon-weight, 400);
  font-size: var(--ax-sys-icon-size, 100%);
}
.ax-icon-more-horizontal:before {
  content: variables.$ax-icon-more-horizontal;
}
.ax-icon-more-horizontal:after {
  content: variables.$ax-icon-more-horizontal-after;
}
.ax-icon-more-vertical:before {
  content: variables.$ax-icon-more-vertical;
}
.ax-icon-more-vertical:after {
  content: variables.$ax-icon-more-vertical-after;
}
